import { useMemo } from "react";
import { useParams, useSearchParams } from "react-router-dom";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { Reveal } from "@/components/landing/motion";
import ItemDetailContent from "@/components/landing/ItemDetailContent";

// Dedicated page for an item at /item/<key>. Renders the same
// ItemDetailContent body as the right-side drawer but in a full-page
// layout (site header + main). The X close button is hidden because
// the user has browser back + the in-page Back button + site nav.
//
// Trail-seller clicks and sparkline point clicks set
// ?sellerView=<name> on the current URL, which causes the global
// DetailDrawer to open the seller overlay on top of this page — the
// same overlay UX as in drawer mode.

export default function ItemDetail() {
  const { key: rawKey } = useParams();
  const [searchParams, setSearchParams] = useSearchParams();

  const itemKey = useMemo(() => {
    try { return decodeURIComponent(rawKey || ""); } catch { return rawKey || ""; }
  }, [rawKey]);

  const openSeller = (name) => {
    const next = new URLSearchParams(searchParams);
    next.set("sellerView", name);
    setSearchParams(next);
  };

  return (
    <div data-testid="item-detail-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-24 pb-16">
        <Reveal className="max-w-4xl mx-auto px-6 md:px-12">
          <ItemDetailContent itemKey={itemKey} onOpenSeller={openSeller} />
        </Reveal>
      </main>
      <Footer />
    </div>
  );
}
