import { motion } from "framer-motion";

// Reusable fade-up reveal on viewport entrance
export const fadeUp = {
  hidden: { opacity: 0, y: 32 },
  show: (i = 0) => ({
    opacity: 1,
    y: 0,
    transition: {
      delay: i * 0.06,
      duration: 0.7,
      ease: [0.16, 1, 0.3, 1],
    },
  }),
};

export const fadeScale = {
  hidden: { opacity: 0, scale: 0.96 },
  show: (i = 0) => ({
    opacity: 1,
    scale: 1,
    transition: {
      delay: i * 0.06,
      duration: 0.7,
      ease: [0.16, 1, 0.3, 1],
    },
  }),
};

export const stagger = {
  hidden: {},
  show: {
    transition: { staggerChildren: 0.08, delayChildren: 0.05 },
  },
};

export function Reveal({ children, delay = 0, y = 32, className = "", as = "div", ...rest }) {
  const MotionComp = motion[as] || motion.div;
  return (
    <MotionComp
      initial={{ opacity: 0, y }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-80px" }}
      transition={{ delay, duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
      className={className}
      {...rest}
    >
      {children}
    </MotionComp>
  );
}

export function RevealStagger({ children, className = "", ...rest }) {
  return (
    <motion.div
      initial="hidden"
      whileInView="show"
      viewport={{ once: true, margin: "-80px" }}
      variants={stagger}
      className={className}
      {...rest}
    >
      {children}
    </motion.div>
  );
}

export function StaggerItem({ children, i = 0, className = "", variant = fadeUp, ...rest }) {
  return (
    <motion.div custom={i} variants={variant} className={className} {...rest}>
      {children}
    </motion.div>
  );
}

// Animated counter that counts up to a target
export function CountUp({ value, format = (v) => v.toLocaleString(), className = "" }) {
  return (
    <motion.span
      className={className}
      initial={{ opacity: 0 }}
      whileInView={{ opacity: 1 }}
      viewport={{ once: true }}
      transition={{ duration: 0.6 }}
    >
      {format(value)}
    </motion.span>
  );
}
